+            PlanNode::Timeout { child, duration } => {
+                let child_ec = dag_to_egraph_rec(dag, child, eg, cache);
+                eg.add_timeout(child_ec, duration)
+            }
+        };
+        cache.insert(id, eclass);
+        eclass
+    }
